# Epic Title: Monitor user behavior metrics

import logging
from flask import Blueprint, jsonify
from backend.analytics.repositories.user_behavior_repository import UserBehaviorRepository

behavior_bp = Blueprint('behavior', __name__)
behavior_repository = UserBehaviorRepository(db_config={'host': 'localhost', 'user': 'root', 'password': '', 'database': 'ecommerce'})

@behavior_bp.route('/user/session-duration', methods=['GET'])
def get_session_duration():
    average_duration = behavior_repository.get_average_session_duration()
    return jsonify({'average_session_duration': average_duration}), 200

@behavior_bp.route('/user/page-views', methods=['GET'])
def get_page_views():
    total_views = behavior_repository.get_total_page_views()
    return jsonify({'total_page_views': total_views}), 200

@behavior_bp.route('/user/click-through-rates', methods=['GET'])
def get_click_rates():
    click_rates = behavior_repository.get_click_through_rates()
    return jsonify({'click_through_rates': click_rates}), 200

# Epic Title: Monitor User Behavior Metrics

from sqlalchemy.orm import Session
from backend.analytics.models.behavior_metric import BehaviorMetric

class BehaviorMetricRepository:
    def __init__(self, db: Session):
        self.db = db

    def get_metrics_by_user_id(self, user_id: int) -> list:
        return self.db.query(BehaviorMetric).filter(BehaviorMetric.user_id == user_id).all()

    def create_metric(self, user_id: int, session_duration: float, page_views: int, click_through_rate: float) -> BehaviorMetric:
        metric = BehaviorMetric(
            user_id=user_id,
            session_duration=session_duration,
            page_views=page_views,
            click_through_rate=click_through_rate
        )
        self.db.add(metric)
        self.db.commit()
        self.db.refresh(metric)
        return metric

# Epic Title: Track Sales Performance Metrics

from sqlalchemy.orm import Session
from backend.analytics.models.sales import Sales

class SalesRepository:
    def __init__(self, db: Session):
        self.db = db

    def get_daily_sales(self, date: str) -> list:
        return self.db.query(Sales).filter(Sales.date == date).all()

    def get_weekly_sales(self, start_date: str, end_date: str) -> list:
        return self.db.query(Sales).filter(Sales.date >= start_date, Sales.date <= end_date).all()

    def get_monthly_sales(self, year: int, month: int) -> list:
        return self.db.query(Sales).filter(Sales.date.year == year, Sales.date.month == month).all()

# Epic Title: Monitor User Behavior Metrics

from sqlalchemy.orm import Session
from backend.analytics.repositories.behavior_metric_repository import BehaviorMetricRepository

class BehaviorMetricService:
    def __init__(self, behavior_metric_repository: BehaviorMetricRepository):
        self.behavior_metric_repository = behavior_metric_repository

    def get_metrics_by_user_id(self, db: Session, user_id: int):
        metrics = self.behavior_metric_repository.get_metrics_by_user_id(user_id)
        avg_session_duration = sum(metric.session_duration for metric in metrics) / len(metrics) if metrics else 0
        total_page_views = sum(metric.page_views for metric in metrics)
        avg_click_through_rate = sum(metric.click_through_rate for metric in metrics) / len(metrics) if metrics else 0
        return {
            "average_session_duration": avg_session_duration,
            "total_page_views": total_page_views,
            "average_click_through_rate": avg_click_through_rate,
            "metrics": metrics
        }

    def create_metric(self, db: Session, user_id: int, session_duration: float, page_views: int, click_through_rate: float) -> dict:
        metric = self.behavior_metric_repository.create_metric(user_id, session_duration, page_views, click_through_rate)
        return {"success": True, "metric": metric}

# Epic Title: Track Sales Performance Metrics

from sqlalchemy.orm import Session
from backend.analytics.repositories.sales_repository import SalesRepository

class SalesService:
    def __init__(self, sales_repository: SalesRepository):
        self.sales_repository = sales_repository

    def get_daily_sales(self, db: Session, date: str):
        sales = self.sales_repository.get_daily_sales(date)
        total_amount = sum(sale.amount for sale in sales)
        return {"date": date, "total_amount": total_amount, "sales": sales}

    def get_weekly_sales(self, db: Session, start_date: str, end_date: str):
        sales = self.sales_repository.get_weekly_sales(start_date, end_date)
        total_amount = sum(sale.amount for sale in sales)
        return {"start_date": start_date, "end_date": end_date, "total_amount": total_amount, "sales": sales}

    def get_monthly_sales(self, db: Session, year: int, month: int):
        sales = self.sales_repository.get_monthly_sales(year, month)
        total_amount = sum(sale.amount for sale in sales)
        return {"year": year, "month": month, "total_amount": total_amount, "sales": sales}
